        raise ValueError("It should be len(wl)>0 and len(flux) > 0. "
                         "Now len(wl)={},len(flux)={}".format(len(wl), len(flux)))
    if len(wl) != len(flux):
        raise ValueError("It should be len(wl) == len(flux). "
                         "Now len(wl)={},len(flux)={}".format(len(wl), len(flux)))

    if z > 0:
        wl_z = wl * (1. + z)
    elif z < 0:
        wl_z = wl / (1. + z)
    else:
        wl_z = wl

