        i_min = np.nonzero(np.greater(wl_z - x_min, 0))[0][0]
    except:
        pass

    i_max = len(wl_z) - 1
    try:
        i_max = np.nonzero(np.greater(wl_z - x_max, 0))[0][0]
    except:
        pass

    if i_min >= 5:
        i_min -= 5
    else:
