    trim_wl = wl_z[i_min:i_max + 1]

    if kind == "spline":
        interp = scipy.interpolate.splrep(self.wl, self.resp_wl, k=1, s=0)
        resp_interp = scipy.interpolate.splev(trim_wl, interp)
    elif kind == 'log':
